{"content":"1: package config
2: 
3: import (
4: 	"errors"
5: 	"fmt"
6: 	"os"
7: 	"path/filepath"
8: 	"time"
9: 
10: 	"github.com/spf13/viper"
11: 	"go.flipt.io/flipt/internal/oci"
12: )
13: 
14: // cheers up the unparam linter
15: var _ defaulter = (*StorageConfig)(nil)
16: 
17: type StorageType string
18: 
19: const (
20: 	DatabaseStorageType = StorageType("database")
21: 	LocalStorageType    = StorageType("local")
22: 	GitStorageType      = StorageType("git")
23: 	ObjectStorageType   = StorageType("object")
24: 	OCIStorageType      = StorageType("oci")
25: )
26: 
27: type ObjectSubStorageType string
28: 
29: const (
30: 	S3ObjectSubStorageType     = ObjectSubStorageType("s3")
31: 	AZBlobObjectSubStorageType = ObjectSubStorageType("azblob")
32: 	GSBlobObjectSubStorageType = ObjectSubStorageType("googlecloud")
33: )
34: 
35: // StorageConfig contains fields which will configure the type of backend in which Flipt will serve
36: // flag state.
37: type StorageConfig struct {
38: 	Type     StorageType `json:"type,omitempty" mapstructure:"type" yaml:"type,omitempty"`
39: 	Local    *Local      `json:"local,omitempty" mapstructure:"local,omitempty" yaml:"local,omitempty"`
40: 	Git      *Git        `json:"git,omitempty" mapstructure:"git,omitempty" yaml:"git,omitempty"`
41: 	Object   *Object     `json:"object,omitempty" mapstructure:"object,omitempty" yaml:"object,omitempty"`
42: 	OCI      *OCI        `json:"oci,omitempty" mapstructure:"oci,omitempty" yaml:"oci,omitempty"`
43: 	ReadOnly *bool       `json:"readOnly,omitempty" mapstructure:"read_only,omitempty" yaml:"read_only,omitempty"`
44: }
45: 
46: func (c *StorageConfig) setDefaults(v *viper.Viper) error {
47: 	switch v.GetString("storage.type") {
48: 	case string(LocalStorageType):
49: 		v.SetDefault("storage.local.path", ".")
50: 	case string(GitStorageType):
51: 		v.SetDefault("storage.git.ref", "main")
52: 		v.SetDefault("storage.git.poll_interval", "30s")
53: 		v.SetDefault("storage.git.insecure_skip_tls", false)
54: 		if v.GetString("storage.git.authentication.ssh.password") != "" ||
55: 			v.GetString("storage.git.authentication.ssh.private_key_path") != "" ||
56: 			v.GetString("storage.git.authentication.ssh.private_key_bytes") != "" {
57: 			v.SetDefault("storage.git.authentication.ssh.user", "git")
58: 		}
59: 	case string(ObjectStorageType):
60: 		// keep this as a case statement in anticipation of
61: 		// more object types in the future
62: 		// nolint:gocritic
63: 		switch v.GetString("storage.object.type") {
64: 		case string(S3ObjectSubStorageType):
65: 			v.SetDefault("storage.object.s3.poll_interval", "1m")
66: 		case string(AZBlobObjectSubStorageType):
67: 			v.SetDefault("storage.object.azblob.poll_interval", "1m")
68: 		case string(GSBlobObjectSubStorageType):
69: 			v.SetDefault("storage.object.googlecloud.poll_interval", "1m")
70: 		}
71: 
72: 	case string(OCIStorageType):
73: 		v.SetDefault("storage.oci.poll_interval", "30s")
74: 		v.SetDefault("storage.oci.manifest_version", "1.1")
75: 
76: 		dir, err := DefaultBundleDir()
77: 		if err != nil {
78: 			return err
79: 		}
80: 
81: 		v.SetDefault("storage.oci.bundles_directory", dir)
82: 
83: 		if v.GetString("storage.oci.authentication.username") != "" ||
84: 			v.GetString("storage.oci.authentication.password") != "" {
85: 			v.SetDefault("storage.oci.authentication.type", oci.AuthenticationTypeStatic)
86: 		}
87: 
88: 	default:
89: 		v.SetDefault("storage.type", "database")
90: 	}
91: 
92: 	return nil
93: }
94: 
95: func (c *StorageConfig) validate() error {
96: 	switch c.Type {
97: 	case GitStorageType:
98: 		if c.Git.Ref == "" {
99: 			return errors.New("git ref must be specified")
100: 		}
101: 		if c.Git.Repository == "" {
102: 			return errors.New("git repository must be specified")
103: 		}
104: 
105: 		if err := c.Git.Authentication.validate(); err != nil {
106: 			return err
107: 		}
108: 		if err := c.Git.validate(); err != nil {
109: 			return err
110: 		}
111: 
112: 	case LocalStorageType:
113: 		if c.Local.Path == "" {
114: 			return errors.New("local path must be specified")
115: 		}
116: 
117: 	case ObjectStorageType:
118: 		if c.Object == nil {
119: 			return errors.New("object storage type must be specified")
120: 		}
121: 		if err := c.Object.validate(); err != nil {
122: 			return err
123: 		}
124: 	case OCIStorageType:
125: 		if c.OCI.Repository == "" {
126: 			return errors.New("oci storage repository must be specified")
127: 		}
128: 
129: 		if c.OCI.ManifestVersion != OCIManifestVersion10 && c.OCI.ManifestVersion != OCIManifestVersion11 {
130: 			return errors.New("wrong manifest version, it should be 1.0 or 1.1")
131: 		}
132: 
133: 		if _, err := oci.ParseReference(c.OCI.Repository); err != nil {
134: 			return fmt.Errorf("validating OCI configuration: %w", err)
135: 		}
136: 
137: 		if c.OCI.Authentication != nil && !c.OCI.Authentication.Type.IsValid() {
138: 			return errors.New("oci authentication type is not supported")
139: 		}
140: 	}
141: 
142: 	// setting read only mode is only supported with database storage
143: 	if c.ReadOnly != nil && !*c.ReadOnly && c.Type != DatabaseStorageType {
144: 		return errors.New("setting read only mode is only supported with database storage")
145: 	}
146: 
147: 	return nil
148: }
149: 
150: // Local contains configuration for referencing a local filesystem.
151: type Local struct {
152: 	Path string `json:"path,omitempty" mapstructure:"path"`
153: }
154: 
155: // Git contains configuration for referencing a git repository.
156: type Git struct {
157: 	Repository      string         `json:"repository,omitempty" mapstructure:"repository" yaml:"repository,omitempty"`
158: 	Ref             string         `json:"ref,omitempty" mapstructure:"ref" yaml:"ref,omitempty"`
159: 	Directory       string         `json:"directory,omitempty" mapstructure:"directory" yaml:"directory,omitempty"`
160: 	CaCertBytes     string         `json:"-" mapstructure:"ca_cert_bytes" yaml:"-" `
161: 	CaCertPath      string         `json:"-" mapstructure:"ca_cert_path" yaml:"-" `
162: 	InsecureSkipTLS bool           `json:"-" mapstructure:"insecure_skip_tls" yaml:"-"`
163: 	PollInterval    time.Duration  `json:"pollInterval,omitempty" mapstructure:"poll_interval" yaml:"poll_interval,omitempty"`
164: 	Authentication  Authentication `json:"-" mapstructure:"authentication,omitempty" yaml:"-"`
165: }
166: 
167: func (g *Git) validate() error {
168: 	if g.CaCertPath != "" && g.CaCertBytes != "" {
169: 		return errors.New("please provide only one of ca_cert_path or ca_cert_bytes")
170: 	}
171: 	return nil
172: }
173: 
174: // Object contains configuration of readonly object storage.
175: type Object struct {
176: 	Type   ObjectSubStorageType `json:"type,omitempty" mapstructure:"type" yaml:"type,omitempty"`
177: 	S3     *S3                  `json:"s3,omitempty" mapstructure:"s3,omitempty" yaml:"s3,omitempty"`
178: 	AZBlob *AZBlob              `json:"azblob,omitempty" mapstructure:"azblob,omitempty" yaml:"azblob,omitempty"`
179: 	GS     *GS                  `json:"googlecloud,omitempty" mapstructure:"googlecloud,omitempty" yaml:"googlecloud,omitempty"`
180: }
181: 
182: // validate is only called if storage.type == "object"
183: func (o *Object) validate() error {
184: 	switch o.Type {
185: 	case S3ObjectSubStorageType:
186: 		if o.S3 == nil || o.S3.Bucket == "" {
187: 			return errors.New("s3 bucket must be specified")
188: 		}
189: 	case AZBlobObjectSubStorageType:
190: 		if o.AZBlob == nil || o.AZBlob.Container == "" {
191: 			return errors.New("azblob container must be specified")
192: 		}
193: 	case GSBlobObjectSubStorageType:
194: 		if o.GS == nil || o.GS.Bucket == "" {
195: 			return errors.New("googlecloud bucket must be specified")
196: 		}
197: 	default:
198: 		return errors.New("object storage type must be specified")
199: 	}
200: 	return nil
201: }
202: 
203: // S3 contains configuration for referencing a s3 bucket
204: type S3 struct {
205: 	Endpoint     string        `json:"endpoint,omitempty" mapstructure:"endpoint" yaml:"endpoint,omitempty"`
206: 	Bucket       string        `json:"bucket,omitempty" mapstructure:"bucket" yaml:"bucket,omitempty"`
207: 	Prefix       string        `json:"prefix,omitempty" mapstructure:"prefix" yaml:"prefix,omitempty"`
208: 	Region       string        `json:"region,omitempty" mapstructure:"region" yaml:"region,omitempty"`
209: 	PollInterval time.Duration `json:"pollInterval,omitempty" mapstructure:"poll_interval" yaml:"poll_interval,omitempty"`
210: }
211: 
212: // AZBlob contains configuration for referencing a Azure Blob Storage
213: type AZBlob struct {
214: 	Endpoint     string        `json:"-" mapstructure:"endpoint" yaml:"endpoint,omitempty"`
215: 	Container    string        `json:"container,omitempty" mapstructure:"container" yaml:"container,omitempty"`
216: 	PollInterval time.Duration `json:"pollInterval,omitempty" mapstructure:"poll_interval" yaml:"poll_interval,omitempty"`
217: }
218: 
219: // GS contains configuration for referencing a Google Cloud Storage
220: type GS struct {
221: 	Bucket       string        `json:"-" mapstructure:"bucket" yaml:"bucket,omitempty"`
222: 	Prefix       string        `json:"prefix,omitempty" mapstructure:"prefix" yaml:"prefix,omitempty"`
223: 	PollInterval time.Duration `json:"pollInterval,omitempty" mapstructure:"poll_interval" yaml:"poll_interval,omitempty"`
224: }
225: 
226: // Authentication holds structures for various types of auth we support.
227: // Token auth will take priority over Basic auth if both are provided.
228: //
229: // To make things easier, if there are multiple inputs that a particular auth method needs, and
230: // not all inputs are given but only partially, we will return a validation error.
231: // (e.g. if username for basic auth is given, and token is also given a validation error will be returned)
232: type Authentication struct {
233: 	BasicAuth *BasicAuth `json:"-" mapstructure:"basic,omitempty" yaml:"-"`
234: 	TokenAuth *TokenAuth `json:"-" mapstructure:"token,omitempty" yaml:"-"`
235: 	SSHAuth   *SSHAuth   `json:"-" mapstructure:"ssh,omitempty" yaml:"-"`
236: }
237: 
238: func (a *Authentication) validate() error {
239: 	if a.BasicAuth != nil {
240: 		if err := a.BasicAuth.validate(); err != nil {
241: 			return err
242: 		}
243: 	}
244: 	if a.TokenAuth != nil {
245: 		if err := a.TokenAuth.validate(); err != nil {
246: 			return err
247: 		}
248: 	}
249: 	if a.SSHAuth != nil {
250: 		if err := a.SSHAuth.validate(); err != nil {
251: 			return err
252: 		}
253: 	}
254: 
255: 	return nil
256: }
257: 
258: // BasicAuth has configuration for authenticating with private git repositories
259: // with basic auth.
260: type BasicAuth struct {
261: 	Username string `json:"-" mapstructure:"username" yaml:"-"`
262: 	Password string `json:"-" mapstructure:"password" yaml:"-"`
263: }
264: 
265: func (b BasicAuth) validate() error {
266: 	if (b.Username != "" && b.Password == "") || (b.Username == "" && b.Password != "") {
267: 		return errors.New("both username and password need to be provided for basic auth")
268: 	}
269: 
270: 	return nil
271: }
272: 
273: // TokenAuth has configuration for authenticating with private git repositories
274: // with token auth.
275: type TokenAuth struct {
276: 	AccessToken string `json:"-" mapstructure:"access_token" yaml:"-"`
277: }
278: 
279: func (t TokenAuth) validate() error { return nil }
280: 
281: // SSHAuth provides configuration support for SSH private key credentials when
282: // authenticating with private git repositories
283: type SSHAuth struct {
284: 	User                  string `json:"-" mapstructure:"user" yaml:"-" `
285: 	Password              string `json:"-" mapstructure:"password" yaml:"-" `
286: 	PrivateKeyBytes       string `json:"-" mapstructure:"private_key_bytes" yaml:"-" `
287: 	PrivateKeyPath        string `json:"-" mapstructure:"private_key_path" yaml:"-" `
288: 	InsecureIgnoreHostKey bool   `json:"-" mapstructure:"insecure_ignore_host_key" yaml:"-"`
289: }
290: 
291: func (a SSHAuth) validate() (err error) {
292: 	defer func() {
293: 		if err != nil {
294: 			err = fmt.Errorf("ssh authentication: %w", err)
295: 		}
296: 	}()
297: 
298: 	if a.Password == "" {
299: 		return errors.New("password required")
300: 	}
301: 
302: 	if (a.PrivateKeyBytes == "" && a.PrivateKeyPath == "") || (a.PrivateKeyBytes != "" && a.PrivateKeyPath != "") {
303: 		return errors.New("please provide exclusively one of private_key_bytes or private_key_path")
304: 	}
305: 
306: 	return nil
307: }
308: 
309: type OCIManifestVersion string
310: 
311: const (
312: 	OCIManifestVersion10 OCIManifestVersion = "1.0"
313: 	OCIManifestVersion11 OCIManifestVersion = "1.1"
314: )
315: 
316: // OCI provides configuration support for OCI target registries as a backend store for Flipt.
317: type OCI struct {
318: 	// Repository is the target repository and reference to track.
319: 	// It should be in the form [<registry>/]<bundle>[:<tag>].
320: 	// When the registry is omitted, the bundle is referenced via the local bundle store.
321: 	// Tag defaults to 'latest' when not supplied.
322: 	Repository string `json:"repository,omitempty" mapstructure:"repository" yaml:"repository,omitempty"`
323: 	// BundlesDirectory is the root directory in which Flipt will store and access local feature bundles.
324: 	BundlesDirectory string `json:"bundlesDirectory,omitempty" mapstructure:"bundles_directory" yaml:"bundles_directory,omitempty"`
325: 	// Authentication configures authentication credentials for accessing the target registry
326: 	Authentication *OCIAuthentication `json:"-,omitempty" mapstructure:"authentication" yaml:"-,omitempty"`
327: 	PollInterval   time.Duration      `json:"pollInterval,omitempty" mapstructure:"poll_interval" yaml:"poll_interval,omitempty"`
328: 	// ManifestVersion defines which OCI Manifest version to use.
329: 	ManifestVersion OCIManifestVersion `json:"manifestVersion,omitempty" mapstructure:"manifest_version" yaml:"manifest_version,omitempty"`
330: }
331: 
332: // OCIAuthentication configures the credentials for authenticating against a target OCI regitstry
333: type OCIAuthentication struct {
334: 	Type     oci.AuthenticationType `json:"-" mapstructure:"type" yaml:"-"`
335: 	Username string                 `json:"-" mapstructure:"username" yaml:"-"`
336: 	Password string                 `json:"-" mapstructure:"password" yaml:"-"`
337: }
338: 
339: func DefaultBundleDir() (string, error) {
340: 	dir, err := Dir()
341: 	if err != nil {
342: 		return "", err
343: 	}
344: 
345: 	bundlesDir := filepath.Join(dir, "bundles")
346: 	if err := os.MkdirAll(bundlesDir, 0755); err != nil {
347: 		return "", fmt.Errorf("creating image directory: %w", err)
348: 	}
349: 
350: 	return bundlesDir, nil
351: }
