			if err := json.Unmarshal(bytes, &man); err != nil {
				return nil, err
			}

			bundle := Bundle{
				Digest:     manifest.Digest,
				Repository: entry.Name(),
				Tag:        manifest.Annotations[v1.AnnotationRefName],
