		switch encoding {
		case "", "json", "yaml", "yml":
		default:
			return nil, fmt.Errorf("layer %q: unexpected layer encoding: %q", layer.Digest, encoding)
		}

		rc, err := store.Fetch(ctx, layer)
		if err != nil {
			return nil, err
		}

		files = append(files, &File{
			ReadCloser: rc,
			info: FileInfo{
				desc:     layer,
				encoding: encoding,
				mod:      created,
			},
		})
