const (
	SchemeHTTP  = "http"
	SchemeHTTPS = "https"
	SchemeFlipt = "flipt"
)

// noOpCache is a cache implementation that doesn't cache anything.
// This is used for AWS ECR credentials which are temporary and should not be cached.
type noOpCache struct{}

func (n *noOpCache) GetScheme(ctx context.Context, registry string) (auth.Scheme, error) {
	return auth.SchemeBearer, nil
}

func (n *noOpCache) GetToken(ctx context.Context, registry string, scheme auth.Scheme, key string) (string, error) {
	return "", nil
}

func (n *noOpCache) Set(ctx context.Context, registry string, scheme auth.Scheme, key string, fetch func(context.Context) (string, error)) (string, error) {
	return fetch(ctx)
}

type credentialFunc func(registry string) auth.CredentialFunc

// Store is a type which can retrieve Flipt feature files from a target repository and reference
// Repositories can be local (OCI layout directories on the filesystem) or a remote registry
type Store struct {
	opts   StoreOptions
	logger *zap.Logger
	local  oras.Target
}

// NewStore constructs and configures an instance of *Store for the provided config
func NewStore(logger *zap.Logger, dir string, opts ...containers.Option[StoreOptions]) (*Store, error) {
	store := &Store{
		opts: StoreOptions{
			bundleDir:       dir,
			manifestVersion: oras.PackManifestVersion1_1,
		},
		logger: logger,
		local:  memory.New(),
	}

	containers.ApplyAll(&store.opts, opts...)

	return store, nil
}

type Reference struct {
	registry.Reference
	Scheme string
}

func ParseReference(repository string) (Reference, error) {
	scheme, repository, match := strings.Cut(repository, "://")
	// support empty scheme as remote and https
	if !match {
		repository = scheme
		scheme = SchemeHTTPS
	}

	if !strings.Contains(repository, "/") {
		repository = "local/" + repository
		scheme = SchemeFlipt
	}

	ref, err := registry.ParseReference(repository)
	if err != nil {
		return Reference{}, err
	}

	switch scheme {
	case SchemeHTTP, SchemeHTTPS:
	case SchemeFlipt:
		if ref.Registry != "local" {
			return Reference{}, fmt.Errorf("unexpected local reference: %q", ref)
		}
	default:
		return Reference{}, fmt.Errorf("unexpected repository scheme: %q should be one of [http|https|flipt]", scheme)
	}

